import (
	"regexp"
	"sort"
)

func solve(code []string, businessLine []string, isActive []bool) []string {
	validBusinessLines := map[string]bool{
		"electronics": true,
		"grocery":     true,
		"pharmacy":    true,
		"restaurant":  true,
	}
	businessLineOrder := map[string]int{
		"electronics": 0,
		"grocery":     1,
		"pharmacy":    2,
		"restaurant":  3,
	}

	var validCoupons []struct {
		code         string
		businessLine string
	}

	validPattern := regexp.MustCompile(`^[a-zA-Z0-9_]+$`)

	for i := 0; i < len(code); i++ {
		if !isActive[i] {
			continue
		}
		if !validBusinessLines[businessLine[i]] {
			continue
		}
		if code[i] == "" || !validPattern.MatchString(code[i]) {
			continue
		}
		validCoupons = append(validCoupons, struct {
			code         string
			businessLine string
		}{code[i], businessLine[i]})
	}

	sort.Slice(validCoupons, func(i, j int) bool {
		orderI := businessLineOrder[validCoupons[i].businessLine]
		orderJ := businessLineOrder[validCoupons[j].businessLine]
		if orderI != orderJ {
			return orderI < orderJ
		}
		return validCoupons[i].code < validCoupons[j].code
	})

	result := make([]string, len(validCoupons))
	for i, coupon := range validCoupons {
		result[i] = coupon.code
	}
	return result
}
